class SSHBruteForceRule(BaseRule):
    name = "ssh_brute_force"
    def __init__(self, threshold=3, window_seconds=60, tracker=None):
        self._threshold = threshold
        self._window = window_seconds
        self._tracker = tracker
        self._failures: dict[str, deque] = defaultdict(deque)
        self._alerted: set[str] = set()

    def feed(self, entry):
        if not isinstance(entry, AuthEntry) or not entry.source_ip or not entry.timestamp:
            return
        ip = entry.source_ip
        if entry.event_type == "failed_password":
            yield from self._handle_failure(entry, ip)
        elif entry.event_type == "accepted_password":
            yield from self._handle_success(entry, ip)

    def _handle_failure(self, entry, ip):
        buf = self._failures[ip]
        buf.append((entry.timestamp, entry.username, entry.raw))
        self._evict(buf, entry.timestamp)
        if self._tracker:
            self._tracker.record(ip, IPEvent(timestamp=entry.timestamp, protocol="ssh", event_type="failure",
                detail=f"Failed password for {entry.username!r} (port {entry.port})"))
        if len(buf) >= self._threshold and ip not in self._alerted:
            self._alerted.add(ip)
            yield Incident(rule_name=self.name, severity=Severity.HIGH, source_ip=ip,
                description=f"SSH brute force: {len(buf)} failed attempts in {self._window}s for user '{entry.username}'",
                evidence=[e[2] for e in buf], first_seen=buf[0][0], last_seen=entry.timestamp, count=len(buf))

    def _handle_success(self, entry, ip):
        if self._tracker:
            self._tracker.record(ip, IPEvent(timestamp=entry.timestamp, protocol="ssh", event_type="success",
                detail=f"Accepted login for {entry.username!r}"))
        buf = self._failures.get(ip)
        if not buf: return
        count = len(buf)
        evidence = [e[2] for e in buf] + [entry.raw]
        first = buf[0][0]
        self._failures[ip] = deque()
        self._alerted.discard(ip)
        yield Incident(rule_name=self.name, severity=Severity.CRITICAL, source_ip=ip,
            description=f"SSH brute force SUCCEEDED: {count} failures then accepted login for '{entry.username}'",
            evidence=evidence, first_seen=first, last_seen=entry.timestamp, count=count + 1)

    def _evict(self, buf, current):
        while buf and (current - buf[0][0]).total_seconds() > self._window:
            buf.popleft()

