_LOGIN_PATHS = {"/login", "/signin", "/auth", "/session", "/wp-login.php"}

class WebBruteForceRule(BaseRule):
    name = "web_brute_force"
    def __init__(self, threshold=3, window_seconds=60, tracker=None):
        self._threshold = threshold
        self._window = window_seconds
        self._tracker = tracker
        self._failures: dict[str, deque] = defaultdict(deque)
        self._alerted: set[str] = set()

    def feed(self, entry):
        if not isinstance(entry, WebEntry) or not entry.source_ip or not entry.timestamp:
            return
        if not self._is_login(entry.path):
            return
        ip = entry.source_ip
        if entry.status_code == 401:
            yield from self._handle_failure(entry, ip)
        elif entry.status_code == 200 and entry.method == "POST":
            yield from self._handle_success(entry, ip)

    def _handle_failure(self, entry, ip):
        buf = self._failures[ip]
        buf.append((entry.timestamp, entry.raw))
        self._evict(buf, entry.timestamp)
        if self._tracker:
            self._tracker.record(ip, IPEvent(timestamp=entry.timestamp, protocol="web", event_type="failure",
                detail=f"401 {entry.method} {entry.path}"))
        if len(buf) >= self._threshold and ip not in self._alerted:
            self._alerted.add(ip)
            yield Incident(rule_name=self.name, severity=Severity.HIGH, source_ip=ip,
                description=f"Web brute force: {len(buf)} failed logins in {self._window}s against '{entry.path}'",
                evidence=[e[1] for e in buf], first_seen=buf[0][0], last_seen=entry.timestamp, count=len(buf))

    def _handle_success(self, entry, ip):
        if self._tracker:
            self._tracker.record(ip, IPEvent(timestamp=entry.timestamp, protocol="web", event_type="success",
                detail=f"200 POST {entry.path}"))
        buf = self._failures.get(ip)
        if not buf: return
        count = len(buf)
        evidence = [e[1] for e in buf] + [entry.raw]
        first = buf[0][0]
        self._failures[ip] = deque()
        self._alerted.discard(ip)
        yield Incident(rule_name=self.name, severity=Severity.CRITICAL, source_ip=ip,
            description=f"Web brute force SUCCEEDED: {count} failures then successful POST to '{entry.path}'",
            evidence=evidence, first_seen=first, last_seen=entry.timestamp, count=count + 1)

    def _is_login(self, path):
        return path in _LOGIN_PATHS or any(p in path for p in _LOGIN_PATHS)

    def _evict(self, buf, current):
        while buf and (current - buf[0][0]).total_seconds() > self._window:
            buf.popleft()

--- analyzer/output.py ---
_COLS = [("SEVERITY",9),("RULE",22),("SOURCE IP",17),("DESCRIPTION",55),("#",4),("FIRST SEEN",19)]
_SEP = " | "
_DIV = "-+-".join("-" * w for _, w in _COLS)

def format_table(incidents):
    if not incidents: return "No incidents detected."
    header = _SEP.join(f"{h:<{w}}" for h, w in _COLS)
    rows = [header, _DIV]
    for inc in sorted(incidents, key=lambda i: (-i.severity.value, i.first_seen or "")):
        ts = inc.first_seen.strftime("%Y-%m-%d %H:%M:%S") if inc.first_seen else "—"  # U+2014 em-dash
        desc = inc.description
        max_w = _COLS[3][1] - 2
        if len(desc) > max_w:
            desc = desc[:max_w] + "..."
        values = [
            (inc.severity.name, _COLS[0][1]),
            (inc.rule_name, _COLS[1][1]),
            (inc.source_ip or "N/A", _COLS[2][1]),
            (desc, _COLS[3][1]),
            (str(inc.count), _COLS[4][1]),
            (ts, _COLS[5][1]),
        ]
        rows.append(_SEP.join(f"{v:<{w}}" for v, w in values))
    return "\n".join(rows)

def print_evidence(incidents):
    for inc in sorted(incidents, key=lambda i: -i.severity.value):
        print(f"\n{'-' * 72}")
        print(f"[{inc.severity.name}] {inc.rule_name}  --  {inc.source_ip or 'N/A'}")
        print(f"  {inc.description}")
        for line in inc.evidence:
            print(f"    | {line}")

